import React from 'react';
import './theme-switcher.css';
const ThemeSwitcher = (props) => (React.createElement("form", { className: `theme-switcher ${props.currentTheme}`, onSubmit: props.onSubmit },
    React.createElement("button", { className: "btn btn-outline btn-outline-dark", type: "submit" },
        "Switch theme (",
        (props.currentTheme === 'light') ? 'Light' : 'Night',
        ")")));
export default ThemeSwitcher;
